   150→pub fn select_provider(
   151→    cards_dir: &Path,
   152→    meta: Option<&mut Meta>,
   153→    stage: &str,
   154→) -> anyhow::Result<Option<ProviderSelection>> {
   155→    let pf = read_providers(cards_dir)?;
   156→    let now = Utc::now().timestamp();
   157→
   158→    let avoid_provider = if stage == "qa" {
   159→        meta.as_ref()
   160→            .and_then(|m| m.stages.get("implement"))
   161→            .and_then(|r| r.provider.clone())
   162→    } else {
   163→        None
   164→    };
   165→
   166→    let chain: Vec<String> = match meta {
   167→        Some(m) => {
   168→            if m.provider_chain.is_empty() {
   169→                m.provider_chain = vec!["mock".to_string(), "mock2".to_string()];
   170→            }
   171→            m.provider_chain.clone()
   172→        }
   173→        None => vec!["mock".to_string(), "mock2".to_string()],
   174→    };
   175→
   176→    let mut fallback: Option<ProviderSelection> = None;
   177→    for name in chain {
   178→        let Some(p) = pf.providers.get(&name) else {
   179→            continue;
   180→        };
   181→        if let Some(until) = p.cooldown_until_epoch_s {
   182→            if until > now {
   183→                continue;
   184→            }
   185→        }
   186→
   187→        if let Some(ref avoid) = avoid_provider {
   188→            if &name == avoid {
   189→                if fallback.is_none() {
   190→                    fallback = Some((
   191→                        name,
   192→                        p.command.clone(),
   193→                        p.rate_limit_exit,
   194→                        p.env.clone(),
   195→                        p.model.clone(),
   196→                    ));
   197→                }
   198→                continue;
   199→            }
   200→        }
   201→
   202→        return Ok(Some((
   203→            name,
   204→            p.command.clone(),
   205→            p.rate_limit_exit,
   206→            p.env.clone(),
   207→            p.model.clone(),
   208→        )));
   209→    }
   210→
   211→    Ok(fallback)
   212→}
