   214→pub fn set_provider_cooldown(
   215→    cards_dir: &Path,
   216→    provider: &str,
   217→    cooldown_s: i64,
   218→) -> anyhow::Result<()> {
   219→    let mut pf = read_providers(cards_dir)?;
   220→    let now = Utc::now().timestamp();
   221→    if let Some(p) = pf.providers.get_mut(provider) {
   222→        p.cooldown_until_epoch_s = Some(now + cooldown_s);
