   190→                    fallback = Some((
   191→                        name,
   192→                        p.command.clone(),
   193→                        p.rate_limit_exit,
   194→                        p.env.clone(),
   195→                        p.model.clone(),
   196→                    ));
   197→                }
   198→                continue;
   199→            }
   200→        }
   201→
   202→        return Ok(Some((
   203→            name,
   204→            p.command.clone(),
   205→            p.rate_limit_exit,
   206→            p.env.clone(),
   207→            p.model.clone(),
   208→        )));
   209→    }
