    64→    /// Read and parse credentials — tries file first, then macOS Keychain.
    65→    ///
    66→    /// Keychain JSON shape: `{"claudeAiOauth":{"accessToken":"...","refreshToken":"..."}}`
    67→    /// File JSON shape:     `{"access_token":"...","refresh_token":"..."}`
    68→    fn read_credentials() -> anyhow::Result<ClaudeCredentials> {
    69→        // Try file first.
    70→        if let Some(path) = Self::credentials_path() {
    71→            if path.exists() {
    72→                let json = std::fs::read_to_string(&path).with_context(|| {
    73→                    format!("cannot read Claude credentials: {}", path.display())
    74→                })?;
    75→                return serde_json::from_str(&json).with_context(|| {
    76→                    format!("malformed Claude credentials at {}", path.display())
    77→                });
    78→            }
    79→        }
    80→        // Fall back to macOS Keychain.
    81→        #[cfg(target_os = "macos")]
    82→        {
    83→            if let Ok(raw) = Self::read_keychain_credentials() {
    84→                return Ok(raw);
    85→            }
    86→        }
    87→        anyhow::bail!("no Claude credentials found (checked file and Keychain)")
